23	const ITEM_REGISTRY: Record<string, ItemTypeInfo> = {
24	  sword: { basePremium: 100, insuranceValue: 1000, isComponent: false },
25	  amulet: { basePremium: 60, insuranceValue: 600, isComponent: false },
26	  staff: { basePremium: 80, insuranceValue: 800, isComponent: false },
27	  potion: { basePremium: 40, insuranceValue: 400, isComponent: false },
28	  rune: { basePremium: 25, insuranceValue: 250, isComponent: true },
29	  moonstone: { basePremium: 25, insuranceValue: 250, isComponent: true },
30	};
31	
32	const itemInfo = (type: string): ItemTypeInfo => {
33	  const info = ITEM_REGISTRY[type];
34	  if (info === undefined) {
35	    throw new Error(`Unknown item type: ${type}`);
36	  }
37	  return info;
38	};
39	
40	const isComponent = (type: string): boolean => itemInfo(type).isComponent;
41	
42	const basePremiumFor = (type: string): number => itemInfo(type).basePremium;
43	
44	const insuranceValueFor = (type: string): number => itemInfo(type).insuranceValue;
45	
46	type Item = {
47	  type: string;
48	  cursed?: boolean;
49	  enchantment?: number;
50	  material?: string;
51	};
52	type QuoteStep = { op: "quote"; items: Item[] };
53	type Damage = { itemType: string; amount: number };
54	type Incident = { cause: string; damages: Damage[] };
55	type ClaimStep = { op: "claim"; policy: number; incident: Incident };
56	type Step = QuoteStep | ClaimStep;
57	type Customer = { yearsWithMHPCO: number };
58	type Scenario = { customer: Customer; steps: Step[] };
59	
60	type Policy = { items: Item[]; remainingCap: number };
61	
62	// Rounding favours MHPCO: premiums round up (customer pays more),
